import os
import tempfile
from google.cloud import storage
import subprocess

def image_conversion(event, context):
    storage_client = storage.Client()

    bucket_name = event['bucket']
    blob_name = event['name']
    blob = storage_client.bucket(bucket_name).get_blob(blob_name)

    _, temp_local_filename = tempfile.mkstemp()

    blob.download_to_filename(temp_local_filename)

    conversion_options = event.get('conversion_options', '-resize 640x480')

    subprocess.call(['convert', conversion_options, temp_local_filename, temp_local_filename])

    blob.upload_from_filename(temp_local_filename)

    os.remove(temp_local_filename)